// Fire sub-workflow for each scene/segment - 2 at a time, 10s between batches
// Avoids Fal.ai 429 rate limits
// Routes per-segment when scene.uses_segments=true (else legacy per-scene)
const { execFileSync, execSync } = require("child_process");

const data = $input.first().json;
const scenes = data.scenes || [];
const segmentsByScene = data.segments_by_scene || {};
const topicId = data.topic_id;
const projectId = data.project_id;
const styleDna = data.style_dna || "";
const registerAnchors = data.register_anchors || "";
const registerNegativeAdditions = data.register_negative_additions || "";
const registerId = data.register_id || "";
const webhookUrl = "http://localhost:5678/webhook/process-scene/image";
const token = $env.DASHBOARD_API_TOKEN;

// Universal negative prompt (prevents artifacts, text, style drift)
const NEGATIVE_PROMPT = "text, watermark, signature, logo, UI elements, blurry, low quality, distorted faces, extra fingers, mutated hands, bad anatomy, deformed, disfigured, out of frame, cropped, duplicate, error, jpeg artifacts, low resolution, cartoon, anime, painting, illustration, 3D render, CGI";

const BATCH_SIZE = 1;
const BATCH_DELAY_SEC = 10;
let fired = 0;
let firedSegments = 0;
let firedScenes = 0;

// Build flat dispatch queue: 1 entry per pending segment (when scene uses segments)
// OR 1 entry per scene (legacy path).
// Resume-safe: scenes with all segments already uploaded just contribute zero entries.
// Defensive only if a scene has uses_segments=true but the topic has zero segment rows
// at all (system-level failure, caught earlier in Prepare Image Data via SEGMENT_FETCH_EMPTY).
const queue = [];
for (const scene of scenes) {
  if (scene.uses_segments === true) {
    const segs = segmentsByScene[scene.id] || [];
    for (const seg of segs) {
      // Only queue still-pending segments (skip already-uploaded on resume)
      if (seg.image_status === 'pending' || !seg.image_status) {
        queue.push({ kind: "segment", scene, seg });
      }
    }
  } else {
    queue.push({ kind: "scene", scene });
  }
}

for (let i = 0; i < queue.length; i += BATCH_SIZE) {
  const batch = queue.slice(i, i + BATCH_SIZE);

  for (const item of batch) {
    const scene = item.scene;
    const prefix = scene.composition_prefix || "";
    let payload;

    if (item.kind === "segment") {
      const seg = item.seg;
      const subject = seg.image_prompt || scene.image_prompt || "";
      const parts = [prefix, subject, registerAnchors, styleDna].filter(Boolean);
      const fullPrompt = parts.join(" ");
      payload = {
        segment_id: seg.id,
        scene_id: scene.id,
        scene_number: scene.scene_number,
        segment_number: seg.segment_number,
        image_prompt: fullPrompt,
        requires_text_rendering: seg.requires_text_rendering === true,
        composition_prefix: scene.composition_prefix || "",
        color_mood: scene.color_mood || "",
        zoom_direction: scene.zoom_direction || "",
        register_id: registerId,
        negative_prompt: registerNegativeAdditions ? (NEGATIVE_PROMPT + ", " + registerNegativeAdditions) : NEGATIVE_PROMPT,
        topic_id: topicId,
        project_id: projectId,
        uses_segments: true
      };
      firedSegments++;
    } else {
      const subject = scene.image_prompt || "";
      const parts = [prefix, subject, registerAnchors, styleDna].filter(Boolean);
      const fullPrompt = parts.join(" ");
      payload = {
        scene_id: scene.id,
        scene_number: scene.scene_number,
        image_prompt: fullPrompt,
        requires_text_rendering: scene.requires_text_rendering === true,
        composition_prefix: scene.composition_prefix || "",
        color_mood: scene.color_mood || "",
        zoom_direction: scene.zoom_direction || "",
        register_id: registerId,
        negative_prompt: registerNegativeAdditions ? (NEGATIVE_PROMPT + ", " + registerNegativeAdditions) : NEGATIVE_PROMPT,
        topic_id: topicId,
        project_id: projectId,
        uses_segments: scene.uses_segments === true
      };
      firedScenes++;
    }

    try {
      execFileSync("curl", [
        "-s", "-o", "/dev/null",
        "-X", "POST", webhookUrl,
        "-H", "Content-Type: application/json",
        "-H", "Authorization: Bearer " + token,
        "-d", JSON.stringify(payload),
        "--connect-timeout", "3",
        "--max-time", "5"
      ]);
      fired++;
    } catch (e) { /* fire-and-forget */ }
  }

  if (i + BATCH_SIZE < queue.length) {
    await new Promise(function(r){setTimeout(r, BATCH_DELAY_SEC*1000);});
  }
}

return [{ json: {
  topic_id: topicId,
  project_id: projectId,
  fired,
  fired_segments: firedSegments,
  fired_scenes: firedScenes,
  total_queue: queue.length,
  total_scenes: scenes.length,
  any_uses_segments: data.any_uses_segments === true,
  batch_size: BATCH_SIZE,
  delay_sec: BATCH_DELAY_SEC,
  has_style_dna: !!styleDna,
  register_id: registerId,
  has_register_anchors: !!registerAnchors
} }];

// Prepare scene data for sliding window processing + fetch style_dna
// Single visual pipeline: all scenes use Fal.ai Seedream 4.0 + FFmpeg Ken Burns.
// FIXED 2026-05-08: was using this.helpers.httpRequest (undefined in task runner sandbox);
// switched to fetch() everywhere. Segment fetch now retries 5x and throws if empty
// (refuses to fall to legacy mode silently).
const scenes = $("Load Fal.ai Scenes").all().map(i => i.json);
const topicId = $("Webhook Trigger").item.json.body.topic_id;
const projectId = $("Load Topic").item.json.project_id;

const SB = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
};

// Flatten if Supabase returned array-in-item
let sceneList = scenes;
if (sceneList.length === 1 && Array.isArray(sceneList[0])) {
  sceneList = sceneList[0];
}

if (!Array.isArray(sceneList) || sceneList.length === 0 || (sceneList.length === 1 && !sceneList[0].id)) {
  return [{
    json: {
      scenes: [],
      topic_id: topicId,
      project_id: projectId,
      total_scenes: 0,
      scenes_completed: 0,
      scenes_failed: 0,
      total_image_cost: 0,
      skip_processing: true,
      style_dna: '',
    }
  }];
}

// Fetch project style_dna
let styleDna = '';
try {
  const r = await fetch(`${SB}/rest/v1/projects?id=eq.${projectId}&select=style_dna`, { headers: sbHeaders });
  const j = await r.json();
  if (Array.isArray(j) && j[0] && j[0].style_dna) styleDna = j[0].style_dna;
  console.log('style_dna fetch: status=' + r.status + ', has_dna=' + (!!styleDna) + ', len=' + (styleDna||'').length);
} catch (e) {
  console.log('style_dna fetch threw (non-fatal): ' + e.message);
}

// Fetch production_register + era from topic + its config from production_registers
let registerId = '';
let registerEra = '';
let registerAnchors = '';
let registerNegativeAdditions = '';
let nicheVariant = '';
try {
  const tr = await fetch(`${SB}/rest/v1/topics?id=eq.${topicId}&select=production_register,register_era_detected,niche_variant`, { headers: sbHeaders });
  const tj = await tr.json();
  if (Array.isArray(tj) && tj[0]) {
    registerId = tj[0].production_register || '';
    registerEra = tj[0].register_era_detected || '';
    nicheVariant = tj[0].niche_variant || '';
  }
  if (registerId) {
    const rr = await fetch(`${SB}/rest/v1/production_registers?register_id=eq.${registerId}&select=config`, { headers: sbHeaders });
    const rj = await rr.json();
    if (Array.isArray(rj) && rj[0] && rj[0].config) {
      const cfg = rj[0].config;
      // 3-branch resolver: era wins -> niche object -> string fallback
      if (cfg.image_anchors_by_era && registerEra && cfg.image_anchors_by_era[registerEra]) {
        registerAnchors = cfg.image_anchors_by_era[registerEra];
      } else if (typeof cfg.image_anchors === 'object' && cfg.image_anchors !== null) {
        const nicheKey = nicheVariant || 'primary';
        registerAnchors = cfg.image_anchors[nicheKey] || cfg.image_anchors.primary || '';
      } else {
        registerAnchors = cfg.image_anchors || '';
      }
      registerNegativeAdditions = cfg.negative_additions || '';
    }
  }
  console.log('register fetch: id=' + registerId + ', era=' + registerEra + ', anchors_len=' + (registerAnchors||'').length + ', neg_len=' + (registerNegativeAdditions||'').length);
} catch (e) {
  console.log('register fetch threw (non-fatal): ' + e.message);
}

// Fetch scene_segments for any scene where uses_segments=true
// Defensive: retry up to 5x on empty result, throw if still empty (never silently fall to legacy)
let segmentsByScene = {};
let anyUsesSegments = false;
const segScenes = sceneList.filter(s => s.uses_segments === true);
if (segScenes.length > 0) {
  anyUsesSegments = true;
  let segRows = [];
  let lastErr = null;
  for (let attempt = 1; attempt <= 5; attempt++) {
    try {
      const r = await fetch(`${SB}/rest/v1/scene_segments?topic_id=eq.${topicId}&order=scene_id.asc,segment_number.asc&select=id,scene_id,segment_number,start_offset_ms,duration_ms,image_prompt,key_visual_anchor,requires_text_rendering,image_status`, { headers: sbHeaders });
      const j = await r.json();
      segRows = Array.isArray(j) ? j : [];
      console.log('segment fetch attempt ' + attempt + ': status=' + r.status + ', got ' + segRows.length + ' rows for ' + segScenes.length + ' scenes');
      if (segRows.length > 0) break;
    } catch (e) {
      lastErr = e;
      console.log('segment fetch attempt ' + attempt + ' threw: ' + e.message);
    }
    if (attempt < 5) await new Promise(r => setTimeout(r, 2000));
  }
  if (segRows.length === 0) {
    throw new Error('SEGMENT_FETCH_EMPTY: ' + segScenes.length + ' scenes have uses_segments=true but scene_segments query returned 0 rows for topic ' + topicId + ' after 5 retries. Last error: ' + (lastErr ? lastErr.message : 'none') + '. Refusing to fall to legacy mode.');
  }
  for (const seg of segRows) {
    if (!segmentsByScene[seg.scene_id]) segmentsByScene[seg.scene_id] = [];
    segmentsByScene[seg.scene_id].push(seg);
  }
  console.log('segmentsByScene populated: ' + Object.keys(segmentsByScene).length + ' scene keys, ' + segRows.length + ' total segments');
}

return [{
  json: {
    scenes: sceneList,
    segments_by_scene: segmentsByScene,
    any_uses_segments: anyUsesSegments,
    topic_id: sceneList[0].topic_id || topicId,
    project_id: projectId,
    total_scenes: sceneList.length,
    scenes_completed: 0,
    scenes_failed: 0,
    total_image_cost: 0,
    skip_processing: false,
    style_dna: styleDna,
    register_id: registerId,
    register_era: registerEra,
    register_anchors: registerAnchors,
    register_negative_additions: registerNegativeAdditions,
    niche_variant: nicheVariant,
  }
}];

// Check how many scenes are still pending
const { execFileSync } = require("child_process");

const topicId = $input.first().json.topic_id;
const projectId = $input.first().json.project_id;
const url = $env.SUPABASE_URL + '/rest/v1/scenes?topic_id=eq.' + topicId + '&image_status=eq.pending&select=id';

const result = execFileSync("curl", [
  "-s", url,
  "-H", "apikey: " + $env.SUPABASE_ANON_KEY,
  "-H", "Authorization: Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY
]).toString();

const pending = JSON.parse(result);
const count = Array.isArray(pending) ? pending.length : 0;

return [{ json: { pending_count: count, topic_id: topicId, project_id: projectId } }];

// Gather final image generation stats from Supabase
const { execFileSync } = require("child_process");

const topicId = $input.first().json.topic_id;
const projectId = $input.first().json.project_id;
const hdr = ["-H", "apikey: " + $env.SUPABASE_ANON_KEY, "-H", "Authorization: Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY];

// Completed scenes (image uploaded)
const uploaded = JSON.parse(execFileSync("curl", ["-s", $env.SUPABASE_URL + '/rest/v1/scenes?topic_id=eq.' + topicId + '&image_status=eq.uploaded&select=id', ...hdr]).toString());
// Failed
const failed = JSON.parse(execFileSync("curl", ["-s", $env.SUPABASE_URL + '/rest/v1/scenes?topic_id=eq.' + topicId + '&image_status=eq.failed&select=id', ...hdr]).toString());

const completed = Array.isArray(uploaded) ? uploaded.length : 0;
const failedCount = Array.isArray(failed) ? failed.length : 0;
// Fal.ai Seedream cost: $0.03 per scene
const totalCost = completed * 0.03;

execFileSync("curl", ["-s", "-X", "PATCH", $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId, ...hdr, "-H", "Content-Type: application/json", "-H", "Prefer: return=minimal", "-d", JSON.stringify({ images_progress: 'complete' })]).toString();

return [{ json: { topic_id: topicId, project_id: projectId, completed, failed: failedCount, total_cost: totalCost, stopped: false } }];

// Completion sync: check if ALL scenes have finished image generation.
// Single visual pipeline: all scenes use Fal.ai Seedream 4.0 â†’ image_status = 'uploaded'.
// After all complete, fires Ken Burns.
const { execFileSync } = require("child_process");

const data = $input.first().json;
const topicId = data.topic_id || $("Webhook Trigger").item.json.body.topic_id;
const projectId = data.project_id || $("Webhook Trigger").item.json.body.project_id;
const hdr = ["-H", "apikey: " + $env.SUPABASE_ANON_KEY, "-H", "Authorization: Bearer " + $env.SUPABASE_SERVICE_ROLE_KEY];

const supaGet = (path) => JSON.parse(execFileSync("curl", ["-s", $env.SUPABASE_URL + '/rest/v1/' + path, ...hdr]).toString());

if (data.stopped) {
  return [{ json: { ...data, topic_id: topicId, project_id: projectId, assembly_claimed: false, reason: 'stopped' } }];
}

// Count completed scenes: image_status=uploaded (all Fal.ai) + any skipped.
const uploaded = supaGet('scenes?topic_id=eq.' + topicId + '&image_status=eq.uploaded&select=id');
const skipped = supaGet('scenes?topic_id=eq.' + topicId + '&skipped=eq.true&select=id');

const completedCount = (Array.isArray(uploaded) ? uploaded.length : 0)
  + (Array.isArray(skipped) ? skipped.length : 0);

const totalScenes = supaGet('scenes?topic_id=eq.' + topicId + '&select=id');
const totalCount = Array.isArray(totalScenes) ? totalScenes.length : 0;

let assemblyClaimed = false;
if (completedCount >= totalCount && totalCount > 0) {
  // Update pipeline_stage to images (completed)
  execFileSync("curl", ["-s", "-X", "PATCH", $env.SUPABASE_URL + '/rest/v1/topics?id=eq.' + topicId, ...hdr, "-H", "Content-Type: application/json", "-H", "Prefer: return=minimal", "-d", JSON.stringify({ pipeline_stage: 'images', images_progress: 'complete' })]);
  assemblyClaimed = true; // Will trigger Ken Burns next
}

return [{ json: { ...data, topic_id: topicId, project_id: projectId, completed_visual_scenes: completedCount, total_visual_scenes: totalCount, assembly_claimed: assemblyClaimed } }];
